// // This module synchronously unloads data from the input D to the output Q on each negative edge of the clock signal when the unload signal is inactive.
module reg_with_load (CLK, LOAD, D, Q);
input CLK, LOAD;
input [3:0] D;
output reg [3:0] Q;

always @(posedge CLK) begin
    if (LOAD)
        Q <= D;
end

endmodule
